    .delete-btn:hover {
      color: var(--danger);
      background-color: rgba(255, 59, 48, 0.08);
    }

    .footer-actions {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-top: 24px;
      padding-top: 16px;
