    .clear-completed-btn {
      background: none;
      border: none;
      color: var(--text-muted);
      font-size: 13px;
      font-weight: 500;
      cursor: pointer;
      transition: color 0.2s;
    }

    .clear-completed-btn:hover {
      color: var(--danger);
    }

    .empty-state {
      text-align: center;
      padding: 48px 0;
      color: var(--text-muted);
    }

    .empty-state svg {
      color: var(--checkbox-empty);
      margin-bottom: 12px;
    }

    .empty-state h3 {
      font-size: 16px;
      font-weight: 600;
      color: var(--text-main);
      margin-bottom: 4px;
    }

    .empty-state p {
      font-size: 13px;
    }

    svg {
      pointer-events: none;
    }
