<body>
  <div class="app-container">
    <header>
      <div class="header-left">
        <h1>Reminders</h1>
        <p id="sub-title">Stay organized today</p>
      </div>
      <span class="counter" id="todo-count">0 remaining</span>
    </header>

    <div class="filter-tabs">
      <button class="filter-tab active" data-filter="all">All</button>
      <button class="filter-tab" data-filter="active">Active</button>
      <button class="filter-tab" data-filter="completed">Completed</button>
    </div>

    <div class="input-form">
      <div class="input-row">
        <input type="text" id="todo-input" placeholder="Add a new task..." autocomplete="off">
      </div>
      <div class="input-options">
        <div class="priority-select">
          <span>Priority:</span>
          <button class="priority-btn active" data-priority="none">None</button>
          <button class="priority-btn" data-priority="low">Low</button>
          <button class="priority-btn" data-priority="medium">Med</button>
          <button class="priority-btn" data-priority="high">High</button>
        </div>
        <button id="add-btn" aria-label="Add Task">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
          Add
        </button>
      </div>
    </div>

    <ul class="todo-list" id="todo-list"></ul>

    <div class="empty-state" id="empty-state" style="display: none;">
      <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round">
        <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path>
        <polyline points="22 4 12 14.01 9 11.01"></polyline>
      </svg>
      <h3>All clear</h3>
      <p>Enjoy your day, or create a new task!</p>
    </div>

    <div class="footer-actions" id="footer-actions" style="display: none;">
      <span style="font-size: 13px; color: var(--text-muted);" id="completed-count">0 completed</span>
      <button class="clear-completed-btn" id="clear-completed">Clear Completed</button>
    </div>
  </div>

  <script>
    const envId = window.__sandboxEnvId;
    const syncKey = "apple_reminders_state";

    let state = {
      items: []
    };

    let currentFilter = 'all';
    let selectedPriority = 'none';

    const todoInput = document.getElementById('todo-input');
    const addBtn = document.getElementById('add-btn');
    const todoList = document.getElementById('todo-list');
    const todoCount = document.getElementById('todo-count');
    const completedCount = document.getElementById('completed-count');
    const emptyState = document.getElementById('empty-state');
    const footerActions = document.getElementById('footer-actions');
    const clearCompletedBtn = document.getElementById('clear-completed');
    const filterTabs = document.querySelectorAll('.filter-tab');
    const priorityButtons = document.querySelectorAll('.priority-btn');

    // Load from Sync API or LocalStorage
    async function loadState() {
      if (envId) {
        try {
          const res = await fetch(`/api/sync/${envId}/${syncKey}`);
          const json = await res.json();
          if (json.data && Array.isArray(json.data.items)) {
            // Avoid re-rendering if active state matches local state
            if (JSON.stringify(state.items) !== JSON.stringify(json.data.items)) {
              state.items = json.data.items;
              render();
            }
          }
        } catch (err) {
          console.error("Failed to fetch state:", err);
        }
      } else {
        const local = localStorage.getItem(syncKey);
        if (local) {
          try {
            const parsed = JSON.parse(local);
            if (Array.isArray(parsed.items)) {
              state.items = parsed.items;
              render();
            }
          } catch (e) {
            console.error(e);
          }
        }
      }
    }

    // Save state
    async function saveState() {
      render();
      if (envId) {
        try {
          await fetch(`/api/sync/${envId}/${syncKey}`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ data: state })
          });
        } catch (err) {
          console.error("Failed to save state:", err);
        }
      } else {
        localStorage.setItem(syncKey, JSON.stringify(state));
      }
    }

    function render() {
      todoList.innerHTML = '';

      const totalActive = state.items.filter(item => !item.completed).length;
      const totalCompleted = state.items.filter(item => item.completed).length;

      todoCount.textContent = `${totalActive} remaining`;
      completedCount.textContent = `${totalCompleted} completed`;

      // Filter state items
      const filteredItems = state.items.filter(item => {
        if (currentFilter === 'active') return !item.completed;
        if (currentFilter === 'completed') return item.completed;
        return true;
      });

      // Update empty state view
      if (filteredItems.length === 0) {
        emptyState.style.display = 'block';
        if (currentFilter === 'completed') {
          emptyState.querySelector('h3').textContent = 'No completed tasks';
          emptyState.querySelector('p').textContent = 'Completed tasks will show up here.';
        } else if (currentFilter === 'active') {
          emptyState.querySelector('h3').textContent = 'No active tasks';
          emptyState.querySelector('p').textContent = 'All tasks are completed!';
        } else {
          emptyState.querySelector('h3').textContent = 'All clear';
          emptyState.querySelector('p').textContent = 'Enjoy your day, or create a new task!';
        }
      } else {
        emptyState.style.display = 'none';
      }

      // Show/hide footer actions
      if (totalCompleted > 0) {
        footerActions.style.display = 'flex';
      } else {
        footerActions.style.display = 'none';
      }

      filteredItems.forEach(item => {
        const li = document.createElement('li');
        li.className = `todo-item ${item.completed ? 'completed' : ''}`;
        li.dataset.id = item.id;

        const checkbox = document.createElement('div');
        checkbox.className = 'todo-checkbox';
        checkbox.addEventListener('click', (e) => {
          e.stopPropagation();
          toggleTodo(item.id);
        });

        const contentDiv = document.createElement('div');
        contentDiv.className = 'todo-content';
        contentDiv.addEventListener('click', () => toggleTodo(item.id));

        const textSpan = document.createElement('span');
        textSpan.className = 'todo-text';
        textSpan.textContent = item.text;

        contentDiv.appendChild(textSpan);

        if (item.priority && item.priority !== 'none') {
          const metaDiv = document.createElement('div');
          metaDiv.className = 'todo-meta';

          const priorityBadge = document.createElement('span');
          priorityBadge.className = `priority-badge ${item.priority}`;
          priorityBadge.textContent = item.priority;

          metaDiv.appendChild(priorityBadge);
          contentDiv.appendChild(metaDiv);
        }

        const actionsWrapper = document.createElement('div');
        actionsWrapper.className = 'actions-wrapper';

        const deleteBtn = document.createElement('button');
        deleteBtn.className = 'delete-btn';
        deleteBtn.ariaLabel = 'Delete Task';
        deleteBtn.innerHTML = `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path><line x1="10" y1="11" x2="10" y2="17"></line><line x1="14" y1="11" x2="14" y2="17"></line></svg>`;
        deleteBtn.addEventListener('click', (e) => {
          e.stopPropagation();
          deleteTodo(item.id);
        });

        actionsWrapper.appendChild(deleteBtn);

        li.appendChild(checkbox);
        li.appendChild(contentDiv);
        li.appendChild(actionsWrapper);
        todoList.appendChild(li);
      });
    }

    function addTodo() {
      const text = todoInput.value.trim();
      if (!text) return;

      const newItem = {
        id: Date.now().toString(),
        text: text,
        completed: false,
        priority: selectedPriority
      };

      state.items.unshift(newItem); // Add new item to the top
      todoInput.value = '';

      // Reset priority select
      selectedPriority = 'none';
      priorityButtons.forEach(btn => {
        if (btn.dataset.priority === 'none') {
          btn.classList.add('active');
        } else {
          btn.classList.remove('active');
        }
      });

      saveState();
    }

    function toggleTodo(id) {
      state.items = state.items.map(item => {
        if (item.id === id) {
          return { ...item, completed: !item.completed };
        }
        return item;
      });
      saveState();
    }

    function deleteTodo(id) {
      state.items = state.items.filter(item => item.id !== id);
      saveState();
    }

    function clearCompleted() {
      state.items = state.items.filter(item => !item.completed);
      saveState();
    }

    // Event listeners for Priority buttons
    priorityButtons.forEach(btn => {
      btn.addEventListener('click', () => {
        priorityButtons.forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
        selectedPriority = btn.dataset.priority;
      });
    });

    // Event listeners for Filter tabs
    filterTabs.forEach(tab => {
      tab.addEventListener('click', () => {
        filterTabs.forEach(t => t.classList.remove('active'));
        tab.classList.add('active');
        currentFilter = tab.dataset.filter;
        render();
      });
    });

    // Event listeners
    todoInput.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') {
        addTodo();
      }
    });

    addBtn.addEventListener('click', addTodo);
    clearCompletedBtn.addEventListener('click', clearCompleted);

    // Initial load and sync setup
    loadState();
    if (envId) {
      setInterval(loadState, 2000);
    }
  </script>
</body>
</html>
